768→+type PreferencesContextValue = {
769→+  uiLanguage: AppLanguage;
770→+  ocrLanguage: AppLanguage;
771→+  setUiLanguage: (lang: AppLanguage) => Promise<void>;
772→+  setOcrLanguage: (lang: AppLanguage) => Promise<void>;
