775→+const PreferencesContext = createContext<PreferencesContextValue | null>(null);
776→+
777→+let preferencesPromise: Promise<{
778→+  uiLanguage: AppLanguage;
779→+  ocrLanguage: AppLanguage;
780→+}> | null = null;
781→+
782→+function getPreferencesPromise(): Promise<{
783→+  uiLanguage: AppLanguage;
784→+  ocrLanguage: AppLanguage;
785→+}> {
786→+  if (!preferencesPromise) {
787→+    preferencesPromise = Promise.all([
788→+      preferencesRepository.getUiLanguage(),
789→+      preferencesRepository.getOcrLanguage(),
790→+    ]).then(([uiLanguage, ocrLanguage]) => {
791→+      i18n.changeLanguage(uiLanguage);
792→+      return { uiLanguage, ocrLanguage };
793→+    });
794→+  }
795→+  return preferencesPromise;
