823→+      setOcrLanguageState(lang);
824→+    },
825→+    []
826→+  );
827→+
828→+  const value = useMemo(
829→+    (): PreferencesContextValue => ({
830→+      uiLanguage,
831→+      ocrLanguage,
832→+      setUiLanguage,
833→+      setOcrLanguage,
834→+    }),
835→+    [uiLanguage, ocrLanguage, setUiLanguage, setOcrLanguage]
